pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

/// Helper function to get the maximum of two integers.
fn imax(i1: i32, i2: i32) -> i32 {
    if i1 > i2 { i1 } else { i2 }
}

/// Helper function to calculate the balance factor of a node.
fn bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let left_depth = if let Some(ref left) = node.borrow().left_child_node {
        left.borrow().depth as i32 + 1
    } else {
        0
    };
    let right_depth = if let Some(ref right) = node.borrow().right_child_node {
        right.borrow().depth as i32 + 1
    } else {
        0
    };
    right_depth - left_depth
}

/// Rotate right around node P.
/// Returns the new top node (L).
fn bostree_rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.as_ref().unwrap().clone();

    // Update parent of L
    let p_parent = p.borrow().parent_node.clone();
    l.borrow_mut().parent_node = p_parent.clone();

    // Update P's parent to point to L
    if let Some(ref parent_weak) = p_parent {
        if let Some(parent) = parent_weak.upgrade() {
            let mut parent_mut = parent.borrow_mut();
            if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, p)) {
                parent_mut.left_child_node = Some(l.clone());
            } else {
                parent_mut.right_child_node = Some(l.clone());
            }
        }
    } else {
        // P was root, now L is root
        tree.root_node = Some(l.clone());
    }

    // P's left becomes L's right
    let l_right = l.borrow().right_child_node.clone();
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l.borrow().right_child_count;
    if let Some(ref right) = l_right {
        right.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    // Update P's depth
    {
        let left_depth = if let Some(ref left) = p.borrow().left_child_node {
            left.borrow().depth + 1
        } else { 0 };
        let right_depth = if let Some(ref right) = p.borrow().right_child_node {
            right.borrow().depth + 1
        } else { 0 };
        p.borrow_mut().depth = imax(left_depth as i32, right_depth as i32) as u32;
    }

    // L's right becomes P
    l.borrow_mut().right_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    // Update L's right_child_count
    l.borrow_mut().right_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;

    // Update L's depth
    {
        let left_depth = if let Some(ref left) = l.borrow().left_child_node {
            left.borrow().depth + 1
        } else { 0 };
        let right_depth = if let Some(ref right) = l.borrow().right_child_node {
            right.borrow().depth + 1
        } else { 0 };
        l.borrow_mut().depth = imax(left_depth as i32, right_depth as i32) as u32;
    }

    l
}

/// Rotate left around node P.
/// Returns the new top node (R).
fn bostree_rotate_left(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.as_ref().unwrap().clone();

    // Update parent of R
    let p_parent = p.borrow().parent_node.clone();
    r.borrow_mut().parent_node = p_parent.clone();

    // Update P's parent to point to R
    if let Some(ref parent_weak) = p_parent {
        if let Some(parent) = parent_weak.upgrade() {
            let mut parent_mut = parent.borrow_mut();
            if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, p)) {
                parent_mut.left_child_node = Some(r.clone());
            } else {
                parent_mut.right_child_node = Some(r.clone());
            }
        }
    } else {
        // P was root, now R is root
        tree.root_node = Some(r.clone());
    }

    // P's right becomes R's left
    let r_left = r.borrow().left_child_node.clone();
    p.borrow_mut().right_child_node = r_left.clone();
    p.borrow_mut().right_child_count = r.borrow().left_child_count;
    if let Some(ref left) = r_left {
        left.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    // Update P's depth
    {
        let left_depth = if let Some(ref left) = p.borrow().left_child_node {
            left.borrow().depth + 1
        } else { 0 };
        let right_depth = if let Some(ref right) = p.borrow().right_child_node {
            right.borrow().depth + 1
        } else { 0 };
        p.borrow_mut().depth = imax(left_depth as i32, right_depth as i32) as u32;
    }

    // R's left becomes P
    r.borrow_mut().left_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

    // Update R's left_child_count
    r.borrow_mut().left_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;

    // Update R's depth
    {
        let left_depth = if let Some(ref left) = r.borrow().left_child_node {
            left.borrow().depth + 1
        } else { 0 };
        let right_depth = if let Some(ref right) = r.borrow().right_child_node {
            right.borrow().depth + 1
        } else { 0 };
        r.borrow_mut().depth = imax(left_depth as i32, right_depth as i32) as u32;
    }

    r
}

impl BOSTree {
    /// Create a new tree with a mandatory comparison function and an optional free function.
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    /// Return the number of nodes in the tree.
    pub fn bostree_node_count(&self) -> u32 {
        if let Some(ref root) = self.root_node {
            root.borrow().left_child_count + root.borrow().right_child_count + 1
        } else {
            0
        }
    }

    /// Insert a new member into the tree and return the associated node.
    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut node_ptr = &mut self.root_node;
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;

        // Find tree position to insert new node
        while let Some(ref mut node) = node_ptr {
            parent_node = Some(node.clone());
            let cmp = (self.cmp_function)(&key, &node.borrow().key);
            if cmp < 0 {
                node.borrow_mut().left_child_count += 1;
                node_ptr = &mut node.borrow_mut().left_child_node;
            } else {
                node.borrow_mut().right_child_count += 1;
                node_ptr = &mut node.borrow_mut().right_child_node;
            }
        }

        // Create new node
        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        *node_ptr = Some(new_node.clone());

        if parent_node.is_none() {
            // Simple case, this is the first node.
            return new_node;
        }

        // Check if the depth changed with the new node
        let mut parent = parent_node.unwrap();

        // If parent has children on both sides after insertion, depth doesn't change
        // Depth only changes if this is the first child on one side
        let parent_has_left = parent.borrow().left_child_node.is_some();
        let parent_has_right = parent.borrow().right_child_node.is_some();

        if (parent_has_left ^ parent_has_right) || (!parent_has_left && !parent_has_right) {
            // This was the first child on one side (or both sides were empty before)
            // Bubble the information up the tree
            parent.borrow_mut().depth += 1;

            while let Some(ref parent_weak) = parent.borrow().parent_node {
                if let Some(grandparent) = parent_weak.upgrade() {
                    let new_left_depth = if let Some(ref left) = grandparent.borrow().left_child_node {
                        left.borrow().depth + 1
                    } else { 0 };
                    let new_right_depth = if let Some(ref right) = grandparent.borrow().right_child_node {
                        right.borrow().depth + 1
                    } else { 0 };

                    let max_depth = imax(new_left_depth as i32, new_right_depth as i32) as u32;

                    if grandparent.borrow().depth != max_depth {
                        grandparent.borrow_mut().depth = max_depth;
                    } else {
                        // Depth didn't change, no need to continue
                        break;
                    }

                    // Check if this node violates the AVL property
                    if new_left_depth as i32 - 2 == new_right_depth as i32 {
                        // Left is two levels deeper than right
                        if bostree_balance(&grandparent.borrow().left_child_node.as_ref().unwrap()) > 0 {
                            bostree_rotate_left(self, &grandparent.borrow().left_child_node.as_ref().unwrap());
                        }
                        parent = bostree_rotate_right(self, &grandparent);
                    } else if new_left_depth as i32 + 2 == new_right_depth as i32 {
                        // Right is two levels deeper than left
                        if bostree_balance(&grandparent.borrow().right_child_node.as_ref().unwrap()) < 0 {
                            bostree_rotate_right(self, &grandparent.borrow().right_child_node.as_ref().unwrap());
                        }
                        parent = bostree_rotate_left(self, &grandparent);
                    } else {
                        parent = grandparent;
                    }
                } else {
                    break;
                }
            }
        }

        new_node
    }

    /// Remove a given node from the tree.
    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = None;

        let (has_left, has_right) = {
            let n = node.borrow();
            (n.left_child_node.is_some(), n.right_child_node.is_some())
        };

        // If this node has children on both sides, bubble one of it upwards
        if has_left && has_right {
            let (candidate, lost_child, bubble_start) = {
                let mut n = node.borrow_mut();
                let (candidate, lost_child) = if n.left_child_node.as_ref().unwrap().borrow().depth >=
                    n.right_child_node.as_ref().unwrap().borrow().depth {
                    // Left branch is deeper
                    n.left_child_count -= 1;
                    let cand = n.left_child_node.as_ref().unwrap().clone();
                    // Find rightmost node in left subtree
                    let mut candidate_ref = cand;
                    while let Some(ref right) = candidate_ref.borrow().right_child_node {
                        candidate_ref.borrow_mut().right_child_count -= 1;
                        candidate_ref = right.clone();
                    }
                    let lost = candidate_ref.borrow().left_child_node.clone();
                    (candidate_ref, lost)
                } else {
                    // Right branch is deeper
                    n.right_child_count -= 1;
                    let cand = n.right_child_node.as_ref().unwrap().clone();
                    // Find leftmost node in right subtree
                    let mut candidate_ref = cand;
                    while let Some(ref left) = candidate_ref.borrow().left_child_node {
                        candidate_ref.borrow_mut().left_child_count -= 1;
                        candidate_ref = left.clone();
                    }
                    let lost = candidate_ref.borrow().right_child_node.clone();
                    (candidate_ref, lost)
                };

                let bubble_start = candidate.borrow().parent_node.clone();
                (candidate, lost_child, bubble_start)
            };

            // Detach candidate from its parent
            if let Some(ref bubble_start_weak) = bubble_start {
                if let Some(bs) = bubble_start_weak.upgrade() {
                    if bs.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate)) {
                        bs.borrow_mut().left_child_node = lost_child.clone();
                    } else {
                        bs.borrow_mut().right_child_node = lost_child.clone();
                    }
                }
            }
            if let Some(ref lost) = lost_child {
                lost.borrow_mut().parent_node = bubble_start;
            }

            // Now replace node with candidate
            // First, save node's connections
            let node_left = node.borrow().left_child_node.clone();
            let node_right = node.borrow().right_child_node.clone();
            let node_parent = node.borrow().parent_node.clone();
            let node_left_count = node.borrow().left_child_count;
            let node_right_count = node.borrow().right_child_count;

            // Set candidate's connections to node's connections
            candidate.borrow_mut().left_child_node = node_left.clone();
            candidate.borrow_mut().right_child_node = node_right.clone();
            candidate.borrow_mut().parent_node = node_parent.clone();
            candidate.borrow_mut().left_child_count = node_left_count;
            candidate.borrow_mut().right_child_count = node_right_count;

            // Update children's parent pointers
            if let Some(ref left) = node_left {
                left.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref right) = node_right {
                right.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Update parent's pointer to candidate
            if let Some(ref parent_weak) = node_parent {
                if let Some(parent) = parent_weak.upgrade() {
                    if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node)) {
                        parent.borrow_mut().left_child_node = Some(candidate.clone());
                    } else {
                        parent.borrow_mut().right_child_node = Some(candidate.clone());
                    }
                }
            } else {
                // Node was root
                self.root_node = Some(candidate.clone());
            }

            // Fixup candidate's depth
            {
                let left_depth = if let Some(ref left) = candidate.borrow().left_child_node {
                    left.borrow().depth + 1
                } else { 0 };
                let right_depth = if let Some(ref right) = candidate.borrow().right_child_node {
                    right.borrow().depth + 1
                } else { 0 };
                candidate.borrow_mut().depth = imax(left_depth as i32, right_depth as i32) as u32;
            }

            // We'll have to fixup child counts and depths up to the root
            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            // Fix immediate parent node child count here
            if let Some(ref bu) = bubble_up {
                if bu.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate)) {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            // Node has children on one side only (or no children)
            if node.borrow().parent_node.is_none() {
                // Node is the root
                let new_root = if node.borrow().left_child_node.is_some() {
                    node.borrow().left_child_node.clone()
                } else {
                    node.borrow().right_child_node.clone()
                };

                self.root_node = new_root.clone();
                if let Some(ref nr) = new_root {
                    nr.borrow_mut().parent_node = None;
                }

                // No rebalancing to do
                bubble_up = None;
            } else {
                let (candidate, candidate_count) = if node.borrow().left_child_node.is_some() {
                    (node.borrow().left_child_node.clone(), node.borrow().left_child_count)
                } else {
                    (node.borrow().right_child_node.clone(), node.borrow().right_child_count)
                };

                if let Some(ref parent_weak) = node.borrow().parent_node {
                    if let Some(parent) = parent_weak.upgrade() {
                        if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node)) {
                            parent.borrow_mut().left_child_node = candidate.clone();
                            parent.borrow_mut().left_child_count = candidate_count;
                        } else {
                            parent.borrow_mut().right_child_node = candidate.clone();
                            parent.borrow_mut().right_child_count = candidate_count;
                        }
                    }
                }

                if let Some(ref cand) = candidate {
                    cand.borrow_mut().parent_node = node.borrow().parent_node.clone();
                }

                bubble_up = node.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            }
        }

        // At this point, everything below and including bubble_start is balanced
        // and we have to look further up.
        let mut bubbling_finished = false;
        while let Some(bu) = bubble_up {
            if !bubbling_finished {
                // Calculate updated depth for bubble_up
                let left_depth = if let Some(ref left) = bu.borrow().left_child_node {
                    left.borrow().depth + 1
                } else { 0 };
                let right_depth = if let Some(ref right) = bu.borrow().right_child_node {
                    right.borrow().depth + 1
                } else { 0 };
                let new_depth = imax(left_depth as i32, right_depth as i32) as u32;
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                // Rebalance bubble_up
                let balance = bostree_balance(&bu);
                if balance < -1 {
                    if bostree_balance(&bu.borrow().left_child_node.as_ref().unwrap()) > 0 {
                        bostree_rotate_left(self, &bu.borrow().left_child_node.as_ref().unwrap());
                    }
                    bubble_up = Some(bostree_rotate_right(self, &bu));
                } else if balance > 1 {
                    if bostree_balance(&bu.borrow().right_child_node.as_ref().unwrap()) < 0 {
                        bostree_rotate_right(self, &bu.borrow().right_child_node.as_ref().unwrap());
                    }
                    bubble_up = Some(bostree_rotate_left(self, &bu));
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                    // Still need to update child counts going up
                    bubble_up = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                }
            }

            if !bubbling_finished {
                // Get the next bubble_up for next iteration
                if let Some(ref bu_ref) = bubble_up {
                    if let Some(ref parent_weak) = bu_ref.borrow().parent_node {
                        if let Some(parent) = parent_weak.upgrade() {
                            if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, bu_ref)) {
                                parent.borrow_mut().left_child_count -= 1;
                            } else {
                                parent.borrow_mut().right_child_count -= 1;
                            }
                        }
                    }
                }
                if bubbling_finished {
                    break;
                }
            } else {
                // Just update child counts
                if let Some(ref parent_weak) = bu.borrow().parent_node {
                    if let Some(parent) = parent_weak.upgrade() {
                        if parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu)) {
                            parent.borrow_mut().left_child_count -= 1;
                        } else {
                            parent.borrow_mut().right_child_count -= 1;
                        }
                    }
                }
                bubble_up = bu.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            }
        }

        // Mark node as invalid and unref
        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    /// Decrease the weak reference count for a node; if that was the last reference,
    /// free the node and return None; otherwise return the node.
    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        {
            let mut n = node.borrow_mut();
            n.weak_ref_count -= 1;
        }

        if node.borrow().weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    /// Lookup a node in the tree by its key.
    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(ref n) = node {
            let cmp = (self.cmp_function)(key, &n.borrow().key);
            if cmp == 0 {
                return Some(n.clone());
            } else if cmp < 0 {
                node = n.borrow().left_child_node.clone();
            } else {
                node = n.borrow().right_child_node.clone();
            }
        }
        None
    }

    /// Return the node at the given in-order index (starting at 0).
    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        let mut idx = index;

        while let Some(ref n) = node {
            let left_count = n.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(n.clone());
                }
                idx -= 1;
                node = n.borrow().right_child_node.clone();
            } else {
                node = n.borrow().left_child_node.clone();
            }
        }
        None
    }

    /// Print the tree (only available in debug builds).
    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        // Debug print - simplified version
        println!("BOSTree print not fully implemented");
    }
}

/// Increase the weak reference count for a node and return the node.
pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = right.clone();
        while let Some(ref left) = current.borrow().left_child_node {
            current = left.clone();
        }
        Some(current)
    } else if let Some(ref parent_weak) = node.borrow().parent_node {
        let mut current = node.clone();
        while let Some(ref parent_weak) = current.borrow().parent_node {
            if let Some(parent) = parent_weak.upgrade() {
                if !parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                    return Some(parent);
                }
                current = parent;
            } else {
                break;
            }
        }
        None
    } else {
        None
    }
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut current = left.clone();
        while let Some(ref right) = current.borrow().right_child_node {
            current = right.clone();
        }
        Some(current)
    } else if let Some(ref parent_weak) = node.borrow().parent_node {
        let mut current = node.clone();
        while let Some(ref parent_weak) = current.borrow().parent_node {
            if let Some(parent) = parent_weak.upgrade() {
                if !parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                    return Some(parent);
                }
                current = parent;
            } else {
                break;
            }
        }
        None
    } else {
        None
    }
}

/// Return the rank (in-order index) of the given node.
pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    while let Some(ref parent_weak) = current.borrow().parent_node {
        if let Some(parent) = parent_weak.upgrade() {
            if parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                counter += 1 + parent.borrow().left_child_count;
            }
            current = parent;
        } else {
            break;
        }
    }

    counter
}
