use std::cell::RefCell;
use std::rc::{Rc, Weak};

#[derive(Debug)]
pub struct BOSTree {
    pub root_node: Option<Rc<RefCell<BOSNode>>>,
    pub cmp_function: BOSTreeCmpFunction,
    pub free_function: Option<BOSTreeFreeFunction>,
}

#[derive(Debug)]
pub struct BOSNode {
    pub left_child_count: u32,
    pub right_child_count: u32,
    pub depth: u32,
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn imax(i1: i32, i2: i32) -> i32 {
    if i1 > i2 { i1 } else { i2 }
}

fn get_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let n = node.borrow();
    let left_depth = n.left_child_node.as_ref().map_or(0, |l| l.borrow().depth as i32 + 1);
    let right_depth = n.right_child_node.as_ref().map_or(0, |r| r.borrow().depth as i32 + 1);
    right_depth - left_depth
}

fn update_depth(node: &Rc<RefCell<BOSNode>>) {
    let (left_depth, right_depth) = {
        let n = node.borrow();
        (
            n.left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1),
            n.right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1),
        )
    };
    node.borrow_mut().depth = imax(left_depth as i32, right_depth as i32) as u32;
}

fn rotate_right(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.as_ref().unwrap().clone();

    // L's right becomes P's left
    let l_right = l.borrow().right_child_node.clone();
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l.borrow().right_child_count;
    if let Some(ref child) = l_right {
        child.borrow_mut().parent_node = Some(Rc::downgrade(&p));
    }

    // Update P's depth
    update_depth(&p);

    // L's right becomes P
    l.borrow_mut().right_child_node = Some(p.clone());
    l.borrow_mut().right_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    // Update L's parent and tree root
    let p_parent = p.borrow().parent_node.clone();
    l.borrow_mut().parent_node = p_parent.clone();

    if let Some(ref parent_weak) = p_parent {
        if let Some(parent) = parent_weak.upgrade() {
            let mut parent_mut = parent.borrow_mut();
            let is_left = parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &p));
            if is_left {
                parent_mut.left_child_node = Some(l.clone());
            } else {
                parent_mut.right_child_node = Some(l.clone());
            }
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    update_depth(&l);
    l
}

fn rotate_left(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.as_ref().unwrap().clone();

    // R's left becomes P's right
    let r_left = r.borrow().left_child_node.clone();
    p.borrow_mut().right_child_node = r_left.clone();
    p.borrow_mut().right_child_count = r.borrow().left_child_count;
    if let Some(ref child) = r_left {
        child.borrow_mut().parent_node = Some(Rc::downgrade(&p));
    }

    // Update P's depth
    update_depth(&p);

    // R's left becomes P
    r.borrow_mut().left_child_node = Some(p.clone());
    r.borrow_mut().left_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

    // Update R's parent and tree root
    let p_parent = p.borrow().parent_node.clone();
    r.borrow_mut().parent_node = p_parent.clone();

    if let Some(ref parent_weak) = p_parent {
        if let Some(parent) = parent_weak.upgrade() {
            let mut parent_mut = parent.borrow_mut();
            let is_left = parent_mut.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &p));
            if is_left {
                parent_mut.left_child_node = Some(r.clone());
            } else {
                parent_mut.right_child_node = Some(r.clone());
            }
        }
    } else {
        tree.root_node = Some(r.clone());
    }

    update_depth(&r);
    r
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        if let Some(ref root) = self.root_node {
            root.borrow().left_child_count + root.borrow().right_child_count + 1
        } else {
            0
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        // Find insertion point
        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;
        let mut current = self.root_node.clone();
        let mut is_left = false;

        while let Some(ref node) = current {
            parent = Some(node.clone());
            let cmp = (self.cmp_function)(&key, &node.borrow().key);
            if cmp < 0 {
                node.borrow_mut().left_child_count += 1;
                current = node.borrow().left_child_node.clone();
                is_left = true;
            } else {
                node.borrow_mut().right_child_count += 1;
                current = node.borrow().right_child_node.clone();
                is_left = false;
            }
        }

        // Create new node
        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        // Attach new node to parent
        if let Some(ref p) = parent {
            if is_left {
                p.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                p.borrow_mut().right_child_node = Some(new_node.clone());
            }
        } else {
            self.root_node = Some(new_node.clone());
        }

        // Update depths and rebalance
        if parent.is_none() {
            return new_node;
        }

        // Check if depth changed and rebalance
        let mut current_parent = parent;
        while let Some(mut node_to_check) = current_parent {
            // Check if this node's depth needs updating
            let (left_depth, right_depth) = {
                let n = node_to_check.borrow();
                (
                    n.left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1),
                    n.right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1),
                )
            };
            let new_depth = imax(left_depth as i32, right_depth as i32) as u32;

            if node_to_check.borrow().depth == new_depth {
                // Depth didn't change, no need to continue up
                break;
            }

            node_to_check.borrow_mut().depth = new_depth;

            // Check AVL balance
            let balance = get_balance(&node_to_check);

            if balance < -1 {
                // Left heavy
                let left = node_to_check.borrow().left_child_node.as_ref().unwrap().clone();
                if get_balance(&left) > 0 {
                    // Left-Right case
                    rotate_left(self, left);
                }
                // Left-Left case
                let parent_of_rotated = node_to_check.borrow().parent_node.clone();
                let rotated = rotate_right(self, node_to_check);
                // Continue up from the rotated node's parent
                current_parent = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                break; // The rotation handles the rest of the tree
            } else if balance > 1 {
                // Right heavy
                let right = node_to_check.borrow().right_child_node.as_ref().unwrap().clone();
                if get_balance(&right) < 0 {
                    // Right-Left case
                    rotate_right(self, right);
                }
                // Right-Right case
                let rotated = rotate_left(self, node_to_check);
                current_parent = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                break;
            } else {
                // Get parent for next iteration
                current_parent = node_to_check.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        // Handle removal of a node with two children
        let node_has_two_children = {
            let n = node.borrow();
            n.left_child_node.is_some() && n.right_child_node.is_some()
        };

        if node_has_two_children {
            // Find replacement node (inorder predecessor or successor)
            let replacement = {
                let n = node.borrow();
                let left_depth = n.left_child_node.as_ref().map_or(0, |l| l.borrow().depth);
                let right_depth = n.right_child_node.as_ref().map_or(0, |r| r.borrow().depth);

                if left_depth >= right_depth {
                    // Use inorder predecessor (rightmost in left subtree)
                    let mut cand = n.left_child_node.as_ref().unwrap().clone();
                    while cand.borrow().right_child_node.is_some() {
                        cand = cand.borrow().right_child_node.as_ref().unwrap().clone();
                    }
                    cand
                } else {
                    // Use inorder successor (leftmost in right subtree)
                    let mut cand = n.right_child_node.as_ref().unwrap().clone();
                    while cand.borrow().left_child_node.is_some() {
                        cand = cand.borrow().left_child_node.as_ref().unwrap().clone();
                    }
                    cand
                }
            };

            // Swap node and replacement data
            let (rep_key, rep_data) = {
                let mut r = replacement.borrow_mut();
                (r.key.clone(), r.data.clone())
            };
            let (node_key, node_data) = {
                let mut n = node.borrow_mut();
                (n.key.clone(), n.data.clone())
            };

            node.borrow_mut().key = rep_key;
            node.borrow_mut().data = rep_data;
            replacement.borrow_mut().key = node_key;
            replacement.borrow_mut().data = node_data;

            // Now remove the replacement node (which has at most one child)
            self.bostree_remove(&replacement);
            return;
        }

        // Node has at most one child
        let child = {
            let n = node.borrow();
            n.left_child_node.clone().or_else(|| n.right_child_node.clone())
        };

        // Update child's parent
        if let Some(ref c) = child {
            c.borrow_mut().parent_node = node.borrow().parent_node.clone();
        }

        // Update parent to point to child
        let node_parent = node.borrow().parent_node.clone();
        if let Some(ref parent_weak) = node_parent {
            if let Some(parent) = parent_weak.upgrade() {
                let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                if is_left {
                    parent.borrow_mut().left_child_node = child.clone();
                } else {
                    parent.borrow_mut().right_child_node = child.clone();
                }
            }
        } else {
            // Node was root
            self.root_node = child.clone();
        }

        // Rebalance up the tree
        let mut bubble_up = node_parent.as_ref().and_then(|w| w.upgrade());
        while let Some(mut current) = bubble_up {
            // Update child counts
            if let Some(ref parent_weak) = current.borrow().parent_node {
                if let Some(parent) = parent_weak.upgrade() {
                    let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current));
                    if is_left {
                        parent.borrow_mut().left_child_count = current.borrow().left_child_count + current.borrow().right_child_count + 1;
                    } else {
                        parent.borrow_mut().right_child_count = current.borrow().left_child_count + current.borrow().right_child_count + 1;
                    }
                }
            }

            // Update depth
            update_depth(&current);

            // Check balance and rebalance
            let balance = get_balance(&current);

            if balance < -1 {
                let left = current.borrow().left_child_node.as_ref().unwrap().clone();
                if get_balance(&left) > 0 {
                    rotate_left(self, left);
                }
                let rotated = rotate_right(self, current);
                bubble_up = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            } else if balance > 1 {
                let right = current.borrow().right_child_node.as_ref().unwrap().clone();
                if get_balance(&right) < 0 {
                    rotate_right(self, right);
                }
                let rotated = rotate_left(self, current);
                bubble_up = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            } else {
                bubble_up = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            }
        }

        // Mark node as invalid and unref
        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        {
            let mut n = node.borrow_mut();
            n.weak_ref_count -= 1;
        }

        if node.borrow().weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(ref n) = node {
            let cmp = (self.cmp_function)(key, &n.borrow().key);
            if cmp == 0 {
                return Some(n.clone());
            } else if cmp < 0 {
                node = n.borrow().left_child_node.clone();
            } else {
                node = n.borrow().right_child_node.clone();
            }
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        let mut idx = index;

        while let Some(ref n) = node {
            let left_count = n.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(n.clone());
                }
                idx -= 1;
                node = n.borrow().right_child_node.clone();
            } else {
                node = n.borrow().left_child_node.clone();
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        println!("BOSTree print not fully implemented");
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = right.clone();
        while let Some(ref left) = current.borrow().left_child_node {
            current = left.clone();
        }
        Some(current)
    } else {
        let mut current = node.clone();
        while let Some(ref parent_weak) = current.borrow().parent_node {
            if let Some(parent) = parent_weak.upgrade() {
                if !parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                    return Some(parent);
                }
                current = parent;
            } else {
                break;
            }
        }
        None
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut current = left.clone();
        while let Some(ref right) = current.borrow().right_child_node {
            current = right.clone();
        }
        Some(current)
    } else {
        let mut current = node.clone();
        while let Some(ref parent_weak) = current.borrow().parent_node {
            if let Some(parent) = parent_weak.upgrade() {
                if !parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                    return Some(parent);
                }
                current = parent;
            } else {
                break;
            }
        }
        None
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    while let Some(ref parent_weak) = current.borrow().parent_node {
        if let Some(parent) = parent_weak.upgrade() {
            if parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                counter += 1 + parent.borrow().left_child_count;
            }
            current = parent;
        } else {
            break;
        }
    }

    counter
}
