pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn imax(i1: i32, i2: i32) -> i32 {
    if i1 > i2 { i1 } else { i2 }
}

fn get_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let (left_depth, right_depth) = {
        let n = node.borrow();
        (
            n.left_child_node.as_ref().map_or(0, |l| l.borrow().depth as i32 + 1),
            n.right_child_node.as_ref().map_or(0, |r| r.borrow().depth as i32 + 1),
        )
    };
    right_depth - left_depth
}

fn update_depth(node: &Rc<RefCell<BOSNode>>) {
    let (left_depth, right_depth) = {
        let n = node.borrow();
        (
            n.left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1),
            n.right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1),
        )
    };
    node.borrow_mut().depth = imax(left_depth as i32, right_depth as i32) as u32;
