fn rotate_right(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    // Extract needed values from p and l
    let (l, l_right, l_right_count, p_parent) = {
        let p_borrow = p.borrow();
        let l_rc = p_borrow.left_child_node.as_ref().unwrap();
        let l_right = l_rc.borrow().right_child_node.clone();
        let l_right_count = l_rc.borrow().right_child_count;
        let p_parent = p_borrow.parent_node.clone();
        (l_rc.clone(), l_right, l_right_count, p_parent)
    };

    // Now p is no longer borrowed, we can mutably borrow it
    // P's left becomes L's right
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l_right_count;
    if let Some(ref child) = l_right {
        child.borrow_mut().parent_node = Some(Rc::downgrade(&p));
    }
    update_depth(&p);

    // L's right becomes P
    l.borrow_mut().right_child_node = Some(p.clone());
    {
        let p_borrow = p.borrow();
        l.borrow_mut().right_child_count = p_borrow.left_child_count + p_borrow.right_child_count + 1;
    }
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

