}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        if let Some(ref root) = self.root_node {
            root.borrow().left_child_count + root.borrow().right_child_count + 1
        } else {
            0
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;
        let mut current = self.root_node.clone();
        let mut is_left_child = false;

        loop {
            let node = match current {
                Some(ref n) => n.clone(),
                None => break,
            };

            parent = Some(node.clone());
            let cmp = (self.cmp_function)(&key, &node.borrow().key);

            if cmp < 0 {
                node.borrow_mut().left_child_count += 1;
                current = node.borrow().left_child_node.clone();
                is_left_child = true;
            } else {
                node.borrow_mut().right_child_count += 1;
                current = node.borrow().right_child_node.clone();
                is_left_child = false;
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some(ref p) = parent {
            if is_left_child {
                p.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                p.borrow_mut().right_child_node = Some(new_node.clone());
            }
        } else {
            self.root_node = Some(new_node.clone());
        }

        if parent.is_none() {
            return new_node;
        }

        let mut current_node = parent;

        while let Some(node_rc) = current_node {
            let (left_depth, right_depth, node_depth) = {
                let n = node_rc.borrow();
                (
                    n.left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1),
                    n.right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1),
                    n.depth,
                )
            };
            let new_depth = imax(left_depth as i32, right_depth as i32) as u32;

            if node_depth == new_depth {
                break;
            }

            node_rc.borrow_mut().depth = new_depth;

            let balance = get_balance(&node_rc);

            if balance < -1 {
                let left = {
                    let n = node_rc.borrow();
                    n.left_child_node.as_ref().unwrap().clone()
                };
                let left_balance = get_balance(&left);
                if left_balance > 0 {
                    rotate_left(self, left);
                }
                let rotated = rotate_right(self, node_rc.clone());
                current_node = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                break;
            } else if balance > 1 {
                let right = {
                    let n = node_rc.borrow();
                    n.right_child_node.as_ref().unwrap().clone()
                };
                let right_balance = get_balance(&right);
                if right_balance < 0 {
                    rotate_right(self, right);
                }
                let rotated = rotate_left(self, node_rc.clone());
                current_node = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                break;
            } else {
                current_node = {
                    let n = node_rc.borrow();
                    n.parent_node.as_ref().and_then(|w| w.upgrade())
                };
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let node_has_two_children = {
            let n = node.borrow();
            n.left_child_node.is_some() && n.right_child_node.is_some()
        };

        if node_has_two_children {
            let replacement = {
                let n = node.borrow();
                let left = n.left_child_node.as_ref().unwrap().clone();
                let right = n.right_child_node.as_ref().unwrap().clone();
                let left_depth = left.borrow().depth;
                let right_depth = right.borrow().depth;

                if left_depth >= right_depth {
                    let mut cand = left;
                    loop {
                        let next = cand.borrow().right_child_node.clone();
                        match next {
                            Some(ref right) => cand = right.clone(),
                            None => break,
                        }
                    }
                    cand
                } else {
                    let mut cand = right;
                    loop {
                        let next = cand.borrow().left_child_node.clone();
                        match next {
                            Some(ref left) => cand = left.clone(),
                            None => break,
                        }
                    }
                    cand
                }
            };

            let (rep_key, rep_data) = {
                let r = replacement.borrow();
                (r.key.clone(), r.data.clone())
            };
            let (node_key, node_data) = {
                let n = node.borrow();
                (n.key.clone(), n.data.clone())
            };

            node.borrow_mut().key = rep_key;
            node.borrow_mut().data = rep_data;
            replacement.borrow_mut().key = node_key;
            replacement.borrow_mut().data = node_data;

            self.bostree_remove(&replacement);
            return;
        }

        // Decrement child counts for all ancestors
        // We need to track whether we're in the left or right subtree of each ancestor
        {
            let mut current = node.clone();
            loop {
                let parent_weak = {
                    let n = current.borrow();
                    n.parent_node.clone()
                };
                match parent_weak {
                    Some(ref pw) => {
                        if let Some(parent) = pw.upgrade() {
                            // Check if current node is the left or right child of parent
                            let is_left_child = {
                                let p = parent.borrow();
                                p.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current))
                            };
                            if is_left_child {
                                parent.borrow_mut().left_child_count -= 1;
                            } else {
                                parent.borrow_mut().right_child_count -= 1;
                            }
                            current = parent;
                        } else {
                            break;
                        }
                    }
                    None => break,
                }
            }
        }

        let child = {
            let n = node.borrow();
            n.left_child_node.clone().or_else(|| n.right_child_node.clone())
        };

        if let Some(ref c) = child {
            c.borrow_mut().parent_node = {
                let n = node.borrow();
                n.parent_node.clone()
            };
        }

        let node_parent = {
            let n = node.borrow();
            n.parent_node.clone()
        };
        if let Some(ref parent_weak) = node_parent {
            if let Some(parent) = parent_weak.upgrade() {
                let is_left = {
                    let p = parent.borrow();
                    p.left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node))
                };
                if is_left {
                    parent.borrow_mut().left_child_node = child.clone();
                } else {
                    parent.borrow_mut().right_child_node = child.clone();
                }
            }
        } else {
            self.root_node = child.clone();
        }

        // Rebalance up the tree
        let mut current_node = node_parent.as_ref().and_then(|w| w.upgrade());

        while let Some(node_rc) = current_node {
            update_depth(&node_rc);

            let balance = get_balance(&node_rc);

            if balance < -1 {
                let left = {
                    let n = node_rc.borrow();
                    n.left_child_node.as_ref().unwrap().clone()
                };
                let left_balance = get_balance(&left);
                if left_balance > 0 {
                    rotate_left(self, left);
                }
                let rotated = rotate_right(self, node_rc.clone());
                current_node = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            } else if balance > 1 {
                let right = {
                    let n = node_rc.borrow();
                    n.right_child_node.as_ref().unwrap().clone()
                };
                let right_balance = get_balance(&right);
                if right_balance < 0 {
                    rotate_right(self, right);
                }
                let rotated = rotate_left(self, node_rc.clone());
                current_node = rotated.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            } else {
                current_node = {
                    let n = node_rc.borrow();
                    n.parent_node.as_ref().and_then(|w| w.upgrade())
                };
            }
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        {
            let mut n = node.borrow_mut();
            n.weak_ref_count -= 1;
        }

        if node.borrow().weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();

        loop {
            let node = match current {
                Some(ref n) => n.clone(),
                None => return None,
            };

            let cmp = (self.cmp_function)(key, &node.borrow().key);
            if cmp == 0 {
                return Some(node.clone());
            } else if cmp < 0 {
                current = node.borrow().left_child_node.clone();
            } else {
                current = node.borrow().right_child_node.clone();
            }
        }
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        let mut idx = index;

        loop {
            let node = match current {
                Some(ref n) => n.clone(),
                None => return None,
            };

            let left_count = node.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(node.clone());
                }
                idx -= 1;
                current = node.borrow().right_child_node.clone();
            } else {
                current = node.borrow().left_child_node.clone();
            }
        }
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        println!("BOSTree print not fully implemented");
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = right.clone();
        loop {
            let next = current.borrow().left_child_node.clone();
            match next {
                Some(ref left) => current = left.clone(),
                None => return Some(current),
            }
        }
    } else {
        let mut current = node.clone();
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            match parent_weak {
                Some(ref pw) => {
                    if let Some(parent) = pw.upgrade() {
                        if !parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                            return Some(parent);
                        }
                        current = parent;
                    } else {
                        return None;
                    }
                }
                None => return None,
            }
        }
    }
}

