        }
    } else {
        let mut current = node.clone();
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            match parent_weak {
                Some(ref pw) => {
                    if let Some(parent) = pw.upgrade() {
                        if !parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                            return Some(parent);
                        }
                        current = parent;
                    } else {
                        return None;
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut current = left.clone();
        loop {
            let next = current.borrow().right_child_node.clone();
            match next {
                Some(ref right) => current = right.clone(),
                None => return Some(current),
            }
        }
    } else {
        let mut current = node.clone();
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            match parent_weak {
                Some(ref pw) => {
                    if let Some(parent) = pw.upgrade() {
                        if !parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                            return Some(parent);
                        }
                        current = parent;
                    } else {
                        return None;
                    }
                }
                None => return None,
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();

    loop {
        let parent_weak = current.borrow().parent_node.clone();
        match parent_weak {
            Some(ref pw) => {
                if let Some(parent) = pw.upgrade() {
                    if parent.borrow().right_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &current)) {
                        counter += 1 + parent.borrow().left_child_count;
                    }
                    current = parent;
                } else {
                    break;
                }
            }
            None => break,
        }
    }

    counter
}
